import{_ as a,o,c as t,a3 as r}from"./chunks/framework.CjquFG0V.js";const f=JSON.parse('{"title":"97. Accrued Days Off","description":"","frontmatter":{"title":"97. Accrued Days Off","eba":"Mental Health Services 2024-2028","topics":["hours","rosters"]},"headers":[],"relativePath":"ebas/mental-health/rpn-pen-mho/leave/97-accrued-days-off.md","filePath":"ebas/mental-health/rpn-pen-mho/leave/97-accrued-days-off.md"}'),n={name:"ebas/mental-health/rpn-pen-mho/leave/97-accrued-days-off.md"};function s(l,e,i,c,h,d){return o(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="_97-accrued-days-off" tabindex="-1">97. Accrued Days Off <a class="header-anchor" href="#_97-accrued-days-off" aria-label="Permalink to &quot;97. Accrued Days Off&quot;">​</a></h1><p><strong>97.1</strong> Accrual of ADOs All full-time Employees will accrue an ADO as follows:</p><p><strong>(a)</strong> a full-time Employee rostered to work on shifts of eight hours’ duration will work 152 hours in each four-week roster cycle to be worked as 19 days each of eight hours with an ADO in each four-week roster cycle; and</p><p><strong>(b)</strong> a full-time Employee rostered to work on night shifts of ten hours’ duration will work 190 hours in each five-week roster cycle to be worked as 19 shifts each of 10 hours with an ADO in each five-week roster cycle.</p><p><strong>97.2</strong> Taking of ADOs Wherever practicable, an ADO will be on the date requested by the Employee.</p><p><strong>97.3</strong> Maximum number of ADOs The maximum ADOs which may be accrued in any calendar year is 13.</p><p><strong>97.4</strong> ADOs and annual leave One day of a year’s annual leave period will be regarded as an ADO for which no additional payment is to be made.</p><p><strong>97.5</strong> ADOs on public holidays Where a public holiday falls on a day upon which a full-time Employee would ordinarily have been required to be on duty, but the Employee is on an accrued day off, another day will be determined by the Employer to be taken by the Employee in lieu of the public holiday, such day to be within the same work cycle where practical.</p><p><strong>97.6</strong> ADOs and termination of employment Upon termination of employment if the Employee has:</p><p><strong>(a)</strong> Taken an ADO (in part or whole) in advance of accruing the necessary hours, the salary of the Employee will be reduced by the total ADOs or portion taken in advance; and</p><p><strong>(b)</strong> Untaken ADOs (in part or whole) at the time of termination, the Employee will be paid the untaken ADOs.</p>',11)])])}const u=a(n,[["render",s]]);export{f as __pageData,u as default};
